import{_ as e,o as t,c as r,a0 as s}from"./chunks/framework.jwovEGr5.js";const o="/assets/Pasted%20image%2020251231112430.BKKL0NwK.png",i="/assets/Pasted%20image%2020251231113111.DcI_l9vd.png",l="/assets/Pasted%20image%2020251231112746.BiiLcpGi.png",h="/assets/Pasted%20image%2020251231112845.DYCuGyPq.png",n="/assets/Pasted%20image%2020251231112948.BaQOPKpC.png",p="/assets/Pasted%20image%2020251231115228.CSBB8mHu.png",d="/assets/Pasted%20image%2020251231115541.Bz9c6hC9.png",c="/assets/Pasted%20image%2020251231120209.COAQ77Ll.png",m="/assets/Pasted%20image%2020251231120441.DrXVoAS6.png",u="/assets/Pasted%20image%2020251231121311.Brp0b29G.png",g="/assets/Pasted%20image%2020251231121159.CsJ7Nbo1.png",b="/assets/Pasted%20image%2020251231121409.J89ycZkR.png",q="/assets/Pasted%20image%2020251231121604.Bmy9F18C.png",_="/assets/Pasted%20image%2020251231121716.DqvyonKm.png",P="/assets/Pasted%20image%2020251231121743.ICQTC4Rj.png",A=JSON.parse('{"title":"显示菜单","description":"","frontmatter":{},"headers":[],"relativePath":"appjs/appjs使用教程.md","filePath":"appjs/appjs使用教程.md"}'),f={name:"appjs/appjs使用教程.md"};function j(k,a,x,C,B,S){return t(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="显示菜单" tabindex="-1">显示菜单 <a class="header-anchor" href="#显示菜单" aria-label="Permalink to &quot;显示菜单&quot;">​</a></h1><h2 id="高级" tabindex="-1">高级 <a class="header-anchor" href="#高级" aria-label="Permalink to &quot;高级&quot;">​</a></h2><p>当右上角显示&quot;高级&quot;时，可打开菜单 <img src="'+o+'" alt=""></p><h2 id="双击屏幕" tabindex="-1">双击屏幕 <a class="header-anchor" href="#双击屏幕" aria-label="Permalink to &quot;双击屏幕&quot;">​</a></h2><p>或者双击屏幕，点击菜单 <img src="'+i+'" alt=""></p><h1 id="菜单功能" tabindex="-1">菜单功能 <a class="header-anchor" href="#菜单功能" aria-label="Permalink to &quot;菜单功能&quot;">​</a></h1><h2 id="导入导出题目" tabindex="-1">导入导出题目 <a class="header-anchor" href="#导入导出题目" aria-label="Permalink to &quot;导入导出题目&quot;">​</a></h2><p>适配PC端作业、手机端随堂练习、<s>手机端考试全卷预览</s>（废弃），未显示此选项表示不支持的网页。 <strong>致命bug</strong>：在<strong>全卷预览</strong>页面中，使用此方法自动完成题目，由于操作过快，app未能将题目选项上传至服务器，此时页面显示<strong>已选择</strong>，但交卷后教师端显示你<strong>未选择</strong>，严重时导致<strong>低分补考</strong>！故此功能废弃！</p><h3 id="导入str" tabindex="-1">导入Str <a class="header-anchor" href="#导入str" aria-label="Permalink to &quot;导入Str&quot;">​</a></h3><p>点击后显示题目 <img src="'+l+'" alt=""> 内含提示词，点击复制并发送给豆包 <img src="'+h+'" alt=""> 将结果粘贴至输入框 <img src="'+n+'" alt=""> 点击确定后，自动选择选项。</p><h3 id="导入json" tabindex="-1">导入json <a class="header-anchor" href="#导入json" aria-label="Permalink to &quot;导入json&quot;">​</a></h3><p>当朋友点击<a href="/appjs/appjs使用教程.html#导出题目">导出题目</a>后，并发送给你，输入后确定可直接使用他的答案。 由于选择题乱序，使用json可无视乱序匹配。 如果作业提交后显示正确答案，优先导入正确答案而非选项。</p><h3 id="导出题目" tabindex="-1">导出题目 <a class="header-anchor" href="#导出题目" aria-label="Permalink to &quot;导出题目&quot;">​</a></h3><p>将你的答案分享给朋友，或者记录下来。</p><h2 id="eruda" tabindex="-1">eruda <a class="header-anchor" href="#eruda" aria-label="Permalink to &quot;eruda&quot;">​</a></h2><p>点击显示或隐藏eruda面板，具体eruda是什么，请访问<a href="https://eruda.liriliri.io/zh/docs/" target="_blank" rel="noreferrer">简介 | Eruda</a> 可以用于执行js，管理localStorage等。</p><h2 id="自动化" tabindex="-1">自动化 <a class="header-anchor" href="#自动化" aria-label="Permalink to &quot;自动化&quot;">​</a></h2><p>为当前网页添加进入时js事件，例如人脸识别可以通过调用exit()退出</p><h2 id="编辑网页" tabindex="-1">编辑网页 <a class="header-anchor" href="#编辑网页" aria-label="Permalink to &quot;编辑网页&quot;">​</a></h2><p>娱乐功能，开启或编辑网页，你可以修改成绩显示为100。</p><h2 id="刷新" tabindex="-1">刷新 <a class="header-anchor" href="#刷新" aria-label="Permalink to &quot;刷新&quot;">​</a></h2><p>刷新当前网页，由于app自带缓存功能，脚本可能并未最新版，刷新网页时重置缓存，顺便更新脚本。</p><h2 id="加载url" tabindex="-1">加载url <a class="header-anchor" href="#加载url" aria-label="Permalink to &quot;加载url&quot;">​</a></h2><p>在任意页面使用，切换当前打开的页面。</p><h2 id="个人信息" tabindex="-1">个人信息 <a class="header-anchor" href="#个人信息" aria-label="Permalink to &quot;个人信息&quot;">​</a></h2><p><strong>危险</strong>！由于可以使用js和app进行交互，其中有一项是获取个人信息，且没有任何权限校验。如果你访问恶意网站，可能恶意网站直接通过此方法获取你的个人信息，至少包含<strong>姓名、学号、学校</strong>。本脚本已开源，欢迎大家监督。</p><h1 id="高级功能" tabindex="-1">高级功能 <a class="header-anchor" href="#高级功能" aria-label="Permalink to &quot;高级功能&quot;">​</a></h1><p><img src="'+p+'" alt=""></p><h2 id="修改" tabindex="-1">修改 <a class="header-anchor" href="#修改" aria-label="Permalink to &quot;修改&quot;">​</a></h2><p>仅在随堂练习提交后，想修改时生效。</p><h2 id="菜单" tabindex="-1">菜单 <a class="header-anchor" href="#菜单" aria-label="Permalink to &quot;菜单&quot;">​</a></h2><p>唤醒<a href="/appjs/appjs使用教程.html#菜单功能">菜单功能</a></p><h2 id="浏览器打开" tabindex="-1">浏览器打开 <a class="header-anchor" href="#浏览器打开" aria-label="Permalink to &quot;浏览器打开&quot;">​</a></h2><p>在浏览器打开当前网页，由与一些网页仅在app中使用，强制打开会出现各种bug。</p><h2 id="网页文字" tabindex="-1">网页文字 <a class="header-anchor" href="#网页文字" aria-label="Permalink to &quot;网页文字&quot;">​</a></h2><p>显示当前网页的文字，可一键复制，偷懒。 <img src="'+d+'" alt=""></p><h2 id="加载url-1" tabindex="-1">加载url <a class="header-anchor" href="#加载url-1" aria-label="Permalink to &quot;加载url&quot;">​</a></h2><p>与<a href="/appjs/appjs使用教程.html#加载url">加载url</a>相同。</p><h2 id="pc中心" tabindex="-1">PC中心 <a class="header-anchor" href="#pc中心" aria-label="Permalink to &quot;PC中心&quot;">​</a></h2><p>用于跳转至<a href="/appjs/appjs使用教程.html#导入导出题目">导入导出题目</a>，因为作业只在PC端提供功能。</p><h2 id="位置库" tabindex="-1">位置库 <a class="header-anchor" href="#位置库" aria-label="Permalink to &quot;位置库&quot;">​</a></h2><p>在位置签到中使用，可以识别已签到位置，或者未签到时已获取位置，或直接为空由用户输入。 <img src="'+c+'" alt=""> 添加后下次签到可一键签到，无需打开位置设置 <img src="'+m+'" alt=""></p><h1 id="不可见功能" tabindex="-1">不可见功能 <a class="header-anchor" href="#不可见功能" aria-label="Permalink to &quot;不可见功能&quot;">​</a></h1><p>非用户输入，自动执行，写死在代码中。</p><h2 id="强兼其他网页" tabindex="-1">强兼其他网页 <a class="header-anchor" href="#强兼其他网页" aria-label="Permalink to &quot;强兼其他网页&quot;">​</a></h2><p>由于显示<a href="/appjs/appjs使用教程.html#高级">高级</a>需要js支持，很多网页并没有这些js，此时许多功能残废。使用以下代码向网页插入所需js，使得适配大多数网页。 <img src="'+u+'" alt=""> 其中AppUtils依赖jsBridge依赖jQuery。</p><h2 id="科技改变考试" tabindex="-1">科技改变考试 <a class="header-anchor" href="#科技改变考试" aria-label="Permalink to &quot;科技改变考试&quot;">​</a></h2><p>通过以下代码，可以去除考试需升级客户端检测。 <img src="'+g+'" alt=""></p><h2 id="优化体验" tabindex="-1">优化体验 <a class="header-anchor" href="#优化体验" aria-label="Permalink to &quot;优化体验&quot;">​</a></h2><p>允许切屏、填空题粘贴答案…… <img src="'+b+'" alt=""> 允许复制题目，隐藏水印 <img src="'+q+'" alt=""><img src="'+_+'" alt=""></p><h2 id="去除签到记录" tabindex="-1">去除签到记录 <a class="header-anchor" href="#去除签到记录" aria-label="Permalink to &quot;去除签到记录&quot;">​</a></h2><p><img src="'+P+'" alt=""></p>',52)])])}const D=e(f,[["render",j]]);export{A as __pageData,D as default};
